  ('disabled-64311456-moex-00169', 'disabled-64311456', 'disabled-64311456-moex-113-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政指導之敘述，下列何者正確？', '["因行政指導所生之爭議，不得提起行政救濟", "行政指導有關文書，除依法限制公開或不予提供者外，應主動公開", "行政指導具有法律上之直接拘束力", "相對人明確拒絕指導時，行政機關得據此對相對人為不利之處置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "b0de080ab2c6", "answer_pdf_sha1": "a8ba3d546963", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "403", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
